import React from "react";

import ThemeContext from "../context/Theme.context";
import classnames from "classnames";
import { landing, postslist } from "../styles/components/Blog.module.scss";
import {
  main__shell,
  main__shellLight,
} from "../styles/components/Main.module.scss";
import { useContext } from "react";
import { DARK } from "../constants/Themes";
import BlogPostListItem from "./BlogPostListItem";
import BlogTitle from "./BlogTitle";
import BlogFooter from "./BlogFooter";
import Seo from "./SEO";
import { BLOG_DESCRIPTION } from "../constants/Blog";

const Blog = ({ posts }) => {
  const { theme } = useContext(ThemeContext);
  const darkMode = theme === DARK;

  return (
    <main
      className={classnames(
        main__shell,
        darkMode ? null : main__shellLight,
        landing
      )}
    >
      <Seo title={"Blog"} description={BLOG_DESCRIPTION} />
      <BlogTitle />
      <div className={postslist}>
        {posts.map(
          ({
            node: {
              id,
              timeToRead,
              frontmatter: { date, slug, title, author, listingContent },
            },
          }) => (
            <BlogPostListItem
              key={id}
              id={id}
              date={date}
              title={title}
              author={author}
              listingContent={listingContent}
              slug={slug}
              timeToRead={timeToRead}
            />
          )
        )}
      </div>
      <BlogFooter />
    </main>
  );
};

export default Blog;
